INSERT INTO `ai_engine_config` VALUES (315200000000000001,'aider',NULL,NULL,315100000000000001,900,20,'C:\\project\\easymvp',NULL,NULL,NULL,'{}',1,1000000000000000003,1000000000000000001,'2026-04-03 12:00:19','2026-04-03 12:00:19',NULL),(315200000000000002,'openhands',NULL,NULL,315100000000000001,1800,20,'C:\\project\\easymvp','docker run --rm -v \"${env:AI_TASK_WORKTREE_PATH}:/workspace\" -w /workspace -e LLM_API_KEY=\"${env:AI_MODEL_API_KEY}\" -e LLM_MODEL=\"anthropic/${env:AI_MODEL_CODE}\" -e LLM_BASE_URL=\"$(${env:AI_MODEL_BASE_URL} -replace \'/v1$\',\'\')\" -e OPENHANDS_SUPPRESS_BANNER=\"1\" -e SANDBOX_VOLUMES=\"/workspace:/workspace:rw\" -e PIP_INDEX_URL=\"https://mirrors.aliyun.com/pypi/simple/\" -e UV_DEFAULT_INDEX=\"https://mirrors.aliyun.com/pypi/simple/\" -e UV_NO_PROGRESS=\"true\" docker.1panel.live/library/python:3.12-slim bash -lc \"python -m pip install -q uv && uv tool run --python 3.12 openhands --headless --json --override-with-envs --always-approve --exit-without-confirmation -t \'$env:AI_TASK_INSTRUCTION\'\"',NULL,NULL,'{\"runner\": \"docker-cli\"}',1,1000000000000000003,1000000000000000001,'2026-04-03 12:00:19','2026-04-03 13:53:58',NULL),(315200000000000003,'claude_code','https://api.lkeap.cloud.tencent.com/coding/anthropic/v1','sk-sp-ErlXWrTOnFVKB4kNZkJcyN6mHnLBn5d9nyVS8e0QmS4eoYih',315100000000000001,1800,20,'','','','','{\"env_key\": \"ANTHROPIC_API_KEY\"}',0,1000000000000000003,1000000000000000001,'2026-04-06 04:32:02','2026-04-06 07:34:40',NULL),(315200000000000004,'codex_cli','','',0,1800,20,'','','','','{\"env_key\": \"OPENAI_API_KEY\"}',0,1000000000000000003,1000000000000000001,'2026-04-06 04:32:02','2026-04-06 07:34:36',NULL),(315200000000000005,'gemini_cli','','',0,1800,20,'','','','','{\"env_key\": \"GEMINI_API_KEY\"}',0,1000000000000000003,1000000000000000001,'2026-04-06 04:32:02','2026-04-06 07:32:25',NULL),(315200000000000006,'chat',NULL,NULL,NULL,0,0,NULL,NULL,NULL,NULL,NULL,1,1000000000000000003,1000000000000000001,'2026-04-06 0