LOCK TABLES `mvp_config` WRITE;
/*!40000 ALTER TABLE `mvp_config` DISABLE KEYS */;
INSERT INTO `mvp_config` VALUES (1,'watchdog.check_interval','120','int','watchdog','[看门狗] 心跳检测间隔（秒）。看门狗每隔此时间检查一次所有running任务是否存活。默认120秒（2分钟）',0,0,'2026-04-03 16:31:01','2026-04-03 16:31:01',NULL),(2,'watchdog.max_stale_count','3','int','watchdog','[看门狗] 连续无心跳次数阈值。任务连续N次检测无心跳进展则判定为卡死，自动终止并重试。默认3次',0,0,'2026-04-03 16:31:01','2026-04-03 16:31:01',NULL),(3,'watchdog.max_retries','3','int','watchdog','[看门狗] 最大自动重试次数。任务失败后自动重试的上限，超过后升级给架构师进行故障分析。默认3次',0,0,'2026-04-03 16:31:01','2026-04-03 16:31:01',NULL),(4,'scheduler.max_concurrent','20','int','scheduler','[调度器] 最大并发任务数。同时执行的任务上限，超出排队等待。影响资源占用和项目推进速度。默认20',0,0,'2026-04-03 16:31:01','2026-04-03 16:31:01',NULL),(5,'scheduler.poll_interval','2','int','scheduler','[调度器] 调度轮询间隔（秒）。调度器每隔此时间扫描一次待执行任务队列。值越小响应越快但CPU开销越大。默认2秒',0,0,'2026-04-03 16:31:01','2026-04-03 16:31:01',NULL),(6,'review.timeout_seconds','300','int','engine','[审核] 方案审核阶段超时（秒）。AI审核方案的最大耗时，超时自动跳过审核环节。默认300秒（5分钟）',0,0,'2026-04-04 16:04:26','2026-04-04 16:04:26',NULL),(7,'review.auto_fix_batch','1','int','engine','[审核] 预检自动修正batch_no开关。1=预检时自动修正不合理的批次号，0=仅报告不修正。默认1',0,0,'2026-04-04 16:04:26','2026-04-04 16:04:26',NULL),(8,'accept.llm_judge_enabled','1','int','accept','[验收] LLM质量评审开关。1=启用AI评判代码质量，0=退化为纯硬规则裁决。默认1',0,0,'2026-04-05 21:13:13','2026-04-05 21:13:13',NULL),(9,'accept.manual_review_enabled','1','int','accept','[验收] 人工审核开关。1=uncertain决策需人工确认，0=uncertain自动转passed。默认1',0,0,'2026-04-05 21:13:13','2026-04-05 21:13:13',NULL),(10,'accept.llm_judge_project_types','*','string','accept','[验收] LLM Judge适用项目类型。JSON数组如[\"software_dev\",\"game_dev\"]，*或空=全部启用。默认*',0,0,'2026-04-05 21:33:17','2026-04-05 21:33:17',NULL),(11,'accept.manual_review_project_types','*','string','accept','[验收] 人工审核适用项目类型。JSON数组，*或空=全部启用。默认*',0,0,'2026-04-05 21:33:17','2026-04-05 21:33:17',NULL),(12,'accept.project_types','*','string','accept','[验收] Accept验收总开关的项目类型白名单。JSON数组，*或空=全部启用。默认*',0,0,'2026-04-05 21:33:17','2026-04-05 21:33:17',NULL),(13,'workflow.autonomy.enabled','1','autonomy','general','[L4总开关] 自治中台入口开关。关闭=所有自治决策不生效，任务走原调度器逻辑。建议首个开启。依赖：无。宪法保护：是（MetaTuner不可自动修改）',0,0,'2026-04-05 22:32:39','2026-04-06 07:14:09',NULL),(14,'workflow.autonomy.audit_only','1','autonomy','general','[L4安全模式] 仅审计模式。1=只记录决策日志不实际执行动作（安全观测期），0=正式接管执行。建议 enabled 开启后先保持 audit_only=1 运行一周观察。依赖：enabled=1。宪法保护：是',0,0,'2026-04-05 22:32:39','2026-04-06 03:43:36',NULL),(15,'workflow.autonomy.policy_engine_enabled','1','autonomy','general','[L3策略引擎] 策略规则匹配开关。开启后 PolicyEngine 根据 mvp_policy_rule 表匹配触发条件生成动作建议。依赖：enabled=1。宪法保护：否',0,0,'2026-04-05 22:32:39','2026-04-06 03:43:36',NULL),(16,'workflow.autonomy.risk_gate_enabled','1','autonomy','general','[L3风险闸门] 风险闸门开关。开启后 RiskGate 根据 mvp_risk_gate_rule 表检查动作风险，高风险动作自动升级为人工审批。依赖：enabled=1。宪法保护：否',0,0,'2026-04-05 22:32:39','2026-04-06 03:43:36',NULL),(25,'workflow.collab.feishu_enabled','1','int','collab','飞书通知总开关(0关/1开)',0,0,'2026-04-06 00:38:35','2026-04-06 08:01:34',NULL),(26,'workflow.collab.feishu_app_id','cli_a958318b62a19bc3','string','collab','飞书应用 App ID',0,0,'2026-04-06 00:38:35','2026-04-06 08:01:34',NULL),(27,'workflow.collab.feishu_app_secret','25kWb5v5uefrGwh4HCt31dMKLXw06QIE','string','collab','飞书应用 App Secret',0,0,'2026-04-06 00:38:35','2026-04-06 08:01:34',NULL),(28,'workflow.collab.feishu_encrypt_key','25kWb5v5uefrGwh4HCt31dMKLXw06QIE','string','collab','飞书事件回调加密 Key(签名验证)',0,0,'2026-04-06 00:38:35','2026-04-06 08:01:34',NULL),(29,'workflow.collab.feishu_default_notify_user_ids','1000000000000000003','string','collab','降级通知的系统用户ID列表(逗号分隔)',0,0,'2026-04-06 00:38:35','2026-04-06 08:01:34',NULL),(30,'workflow.autonomy.patrol_interval','60','int','autonomy','[L6巡检间隔] 态势巡检间隔（秒）。patrol_enabled=1 时生效，默认60秒。建议生产环境设置 300~600 秒。依赖：patrol_enabled=1',0,0,'2026-04-06 03:36:41','2026-04-06 03:43:36',NULL),(31,'workflow.autonomy.patrol_enabled','0','int','autonomy','[L6态势巡检] 定时巡检开关。开启后 Sensor 按 patrol_interval 间隔定期采集项目态势快照写入 mvp_situation_snapshot。关闭后仅在决策触发时采集。依赖：enabled=1',0,0,'2026-04-06 03:36:41','2026-04-06 03:43:36',NULL),(32,'workflow.autonomy.objective_enabled','0','int','autonomy','[L6目标层] 目标层准入控制开关。开启后 AdmissionControl 在每次决策前检查态势快照是否满足项目目标约束（预算/时间/质量），不满足则拒绝执行。依赖：enabled=1。宪法保护：否',0,0,'2026-04-06 03:36:41','2026-04-06 03:43:36',NULL),(33,'workflow.autonomy.default_token_budget','0','int','autonomy','[L6默认参数] 默认Token预算。0=不限。设置后成本守卫策略会在接近预算时触发降级。依赖：cost_guard_enabled=1',0,0,'2026-04-06 03:36:41','2026-04-06 03:43:36',NULL),(34,'workflow.autonomy.default_time_budget_hours','0','string','autonomy','[L6默认参数] 默认时间预算（小时）。0=不限。设置后 AdmissionControl 会在超时前触发告警或暂停。依赖：objective_enabled=1',0,0,'2026-04-06 03:36:41','2026-04-06 03:43:36',NULL),(35,'workflow.autonomy.default_risk_tolerance','balanced','string','autonomy','[L4默认参数] 默认风险容忍度。conservative=保守(更多人工审批)，balanced=均衡，aggressive=激进(更多自动执行)。影响RiskGate阈值计算',0,0,'2026-04-06 03:36:41','2026-04-06 03:43:36',NULL),(36,'workflow.autonomy.default_autonomy_level','supervised','string','autonomy','[L4默认参数] 默认自治级别。manual=全人工审批，supervised=AI建议+人工确认，autonomous=AI自主执行。新项目继承此值。宪法保护：是（MetaTuner不可自动修改）',0,0,'2026-04-06 03:36:41','2026-04-06 03:43:36',NULL),(37,'workflow.autonomy.strategy_enabled','1','int','autonomy','[L5策略总开关] 策略函数总开关。开启后 Planner 评估6个策略函数（成本守卫/自适应重试/主动重规划/执行器选择/批次调整/质量门）。依赖：enabled=1。宪法保护：否。建议在 audit_only=0 之前开启观察',0,0,'2026-04-06 03:36:47','2026-04-06 07:17:26',NULL),(38,'workflow.autonomy.adaptive_retry_enabled','1','int','autonomy','[L5子策略] 自适应重试策略（优先级90）。任务失败后根据历史成功率智能决定重试/跳过/升级。关闭后回退到固定3次重试。依赖：strategy_enabled=1',0,0,'2026-04-06 03:36:47','2026-04-06 03:43:37',NULL),(39,'workflow.autonomy.engine_selection_enabled','1','int','autonomy','[L5子策略] 执行器选择策略（优先级70）。根据任务特征和历史成功率自动选择最优执行器（aider/claude_code/codex_cli/gemini_cli）。关闭后使用角色预设的默认执行器。依赖：strategy_enabled=1',0,0,'2026-04-06 03:36:47','2026-04-06 03:43:37',NULL),(40,'workflow.autonomy.batch_adjust_enabled','1','int','autonomy','[L5子策略] 批次调整策略（优先级60）。根据并发任务完成情况动态调整批次大小和并行度。关闭后使用固定批次策略。依赖：strategy_enabled=1',0,0,'2026-04-06 03:36:47','2026-04-06 03:43:37',NULL),(41,'workflow.autonomy.cost_guard_enabled','1','int','autonomy','[L5子策略] 成本守卫策略（优先级100）。当Token消耗超预算时触发降级/暂停。关闭后不检查成本。依赖：strategy_enabled=1',0,0,'2026-04-06 03:36:47','2026-04-06 03:43:37',NULL),(42,'workflow.autonomy.proactive_replan_enabled','1','int','autonomy','[L5子策略] 主动重规划策略（优先级70）。连续失败或大面积阻塞时主动触发架构师重新规划。关闭后仅被动等待人工干预。依赖：strategy_enabled=1',0,0,'2026-04-06 03:36:47','2026-04-06 03:43:37',NULL),(43,'workflow.autonomy.quality_gate_enabled','1','int','autonomy','[L5子策略] 质量门策略（优先级50）。审计通过率低于阈值时自动收紧审查标准或暂停流水线。关闭后不做质量自动干预。依赖：strategy_enabled=1',0,0,'2026-04-06 03:36:47','2026-04-06 03:43:37',NULL),(106,'workflow.autonomy.meta_cognition_enabled','1','int','autonomy','[L7观测] 元认知观测开关。开启后 MetaObserver 异步记录每次决策的输入/输出/结果/效果评分到 mvp_observation_record。零副作用，建议早期开启积累数据。依赖：enabled=1。宪法保护：是',0,0,'2026-04-06 04:09:43','2026-04-06 07:15:33',NULL),(107,'workflow.autonomy.meta_auto_tune_enabled','1','int','autonomy','[L7自动校准] 自动校准开关（仅保守方向）。开启后 MetaTuner 对评估偏差自动生成调参建议，保守方向自动应用，激进方向仍需人工审批。依赖：meta_cognition_enabled=1 + learner_enabled=1。宪法保护：是',0,0,'2026-04-06 04:09:43','2026-04-06 07:18:26',NULL),(108,'workflow.autonomy.learner_enabled','1','int','autonomy','[L7学习] EMA学习开关。开启后 Learner 对观测数据做指数移动平均学习，更新 mvp_learning_record。三重保护：样本量≥10/7天衰减/±20%限幅。依赖：meta_cognition_enabled=1。宪法保护：否',0,0,'2026-04-06 04:09:43','2026-04-06 07:18:13',NULL),(109,'autonomy.mode','suggest','string','autonomy','[L4运行模式] 自治运行模式。auto=自动执行决策，suggest=仅建议由人工确认。影响 DecisionCenter 对 A/B 级决策的处理方式。依赖：enabled=1',0,0,'2026-04-06 04:42:57','2026-04-06 07:37:25',NULL),(110,'failure_handoff.max_rounds','3','int','engine','[引擎] Bug闭环修复最大轮次。审计→分析→修复→再审计的循环上限，超限后升级到架构师人工介入。默认3轮',0,0,'2026-04-06 04:42:57','2026-04-06 04:42:57',NULL),(111,'runtime.max_steps','2','int','engine','[引擎] Aider单次执行最大步数。控制Aider CLI的 --max-steps 参数，防止无限循环。默认2',0,0,'2026-04-06 04:42:57','2026-04-06 04:42:57',NULL),(112,'runtime.task_timeout_seconds','600','int','engine','[引擎] 任务执行超时（秒）。Aider/执行器单次执行的最大耗时，超时自动终止。默认600秒（10分钟）',0,0,'2026-04-06 04:42:57','2026-04-06 04:42:57',NULL),(113,'watchdog.heartbeat_timeout.analysis','180','int','watchdog','[看门狗] 分析类任务心跳超时（秒）。架构师/审计员等分析任务的无心跳判定阈值。默认180秒',0,0,'2026-04-06 04:42:57','2026-04-06 04:42:57',NULL),(114,'watchdog.heartbeat_timeout.coding','120','int','watchdog','[看门狗] 编码类任务心跳超时（秒）。实现者代码编辑任务的无心跳判定阈值。默认120秒',0,0,'2026-04-06 04:42:57','2026-04-06 04:42:57',NULL),(115,'watchdog.heartbeat_timeout.creative','300','int','watchdog','[看门狗] 创意类任务心跳超时（秒）。需求设计等创意型任务的无心跳判定阈值，允许更长思考时间。默认300秒',0,0,'2026-04-06 04:42:57','2026-04-06 04:42:57',NULL),(116,'workflow.collab.feishu_verification_token','vVGmDCeqdDZHLCvZwPkDVgrbcWOr4VDA','string','collab','飞书 Verification Token',0,0,'2026-04-06 04:42:57','2026-04-06 08:01:34',NULL),(117,'workflow.scheduler.max_concurrency','20','int','scheduler','[调度器] V2调度器最大并发数。Sensor态势采集时读取此值判断系统负载。与scheduler.max_concurrent含义相同，用于V2链路。默认20',0,0,'2026-04-06 04:42:57','2026-04-06 04:42:57',NULL);
/*!40000 ALTER TABLE `mvp_config` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `mvp_conversation`
--

DROP TABLE IF EXISTS `mvp_conversation`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `mvp_conversation` (
  `id` bigint unsigned NOT NULL COMMENT '雪花ID',
  `project_id` bigint unsigned NOT NULL COMMENT '项目ID',
  `task_id` bigint unsigned DEFAULT NULL COMMENT '关联任务ID，NULL=项目级对话',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '对话标题',
  `role_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '对话角色类型',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active' COMMENT '状态：active/archived',
  `created_by` bigint unsigned DEFAULT NULL COMMENT '创建人ID',
  `dept_id` bigint unsigned DEFAULT NULL COMMENT '所属部门ID',
  `created_at` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_at` datetime DEFAULT NULL COMMENT '更新时间',
  `deleted_at` datetime DEFAULT NULL COMMENT '软删除时间',
  PRIMARY KEY (`id`),
  KEY `idx_project` (`project_id`),
  KEY `idx_task` (`task_id`),
  KEY `idx_deleted_at` (`deleted_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='MVP对话表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
--

LOCK TABLES `mvp_conversation` WRITE;
/*!40000 ALTER TABLE `mvp_conversation` DISABLE KEYS */;
