INSERT INTO `mvp_policy_rule` VALUES (900000000000001,'POL_TASK_FAIL_RETRY','任务失败自动重试','task_recovery','A','task.failed',NULL,NULL,'{\"max_retry\": 3, \"action_type\": \"retry_task\"}',1,10,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000002,'POL_REWORK_DONE_ACCEPT','返工完成回验收','rework_flow','A','rework.completed',NULL,NULL,'{\"action_type\": \"rerun_accept\"}',1,10,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000003,'POL_RETRY_EXHAUST_REWORK','重试耗尽建议返工','task_recovery','B','task.retry_exhausted',NULL,NULL,'{\"action_type\": \"trigger_rework\"}',1,20,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000004,'POL_ACCEPT_FAIL_REWORK','验收失败建议返工','accept_flow','B','accept.failed',NULL,NULL,'{\"action_type\": \"trigger_rework\"}',1,20,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000005,'POL_ACCEPT_PASS_COMPLETE','验收通过建议完成','accept_flow','B','accept.passed',NULL,NULL,'{\"action_type\": \"approve_complete\"}',1,20,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000006,'POL_CIRCUIT_BREAK_PAUSE','熔断暂停','circuit_break','C','workflow.circuit_break',NULL,NULL,'{\"action_type\": \"pause_workflow\"}',1,30,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000007,'POL_ACCEPT_MANUAL','验收人工审核','accept_flow','C','accept.manual_review',NULL,NULL,'{\"action_type\": \"notify_human\"}',1,30,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000008,'POL_REPLAN_SUGGEST','重规划建议','replan','C','replan.suggested',NULL,NULL,'{\"action_type\": \"replan_workflow\"}',1,30,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL);
