INSERT INTO `mvp_risk_gate_rule` VALUES (900000000000101,'GATE_RUNTIME_FAIL_LIMIT','连续失败上限闸门','runtime',NULL,NULL,'{\"trigger_source\": \"task.failed\", \"min_failure_count\": 10}','pause_workflow','notify_human',1,10,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000102,'GATE_QUALITY_REWORK_LIMIT','返工轮次上限闸门','quality',NULL,NULL,'{\"trigger_source\": \"rework.completed\", \"max_rework_rounds\": 5}','pause_workflow','notify_human',1,20,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL),(900000000000103,'GATE_COST_ACCEPT_LIMIT','验收轮次上限闸门','cost',NULL,NULL,'{\"trigger_source\": \"accept.failed\", \"max_accept_rounds\": 5}','pause_workflow','notify_human',1,30,0,0,'2026-04-05 22:33:20','2026-04-06 03:43:36',NULL);
