-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000603,'animation_project','auditor','pro',315100000000000002,'','chat',1,1,30,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000604,'animation_project','coordinator','lite',315100000000000003,'','chat',1,1,40,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000701,'data_analysis','architect','max',315100000000000001,'','chat',1,1,10,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000702,'data_analysis','implementer','pro',315100000000000002,'','auto',1,1,20,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000703,'data_analysis','auditor','pro',315100000000000002,'','chat',1,1,30,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000704,'data_analysis','coordinator','lite',315100000000000003,'','chat',1,1,40,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000801,'product_design','architect','max',315100000000000001,'','chat',1,1,10,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000802,'product_design','implementer','pro',315100000000000002,'','auto',1,1,20,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000803,'product_design','auditor','pro',315100000000000002,'','chat',1,1,30,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000804,'product_design','coordinator','lite',315100000000000003,'','chat',1,1,40,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000901,'software_dev','architect','max',315100000000000001,'','chat',1,1,10,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000902,'software_dev','implementer','pro',315100000000000002,'','auto',1,1,20,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000903,'software_dev','auditor','pro',315100000000000002,'','chat',1,1,30,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(315300000000000904,'software_dev','coordinator','lite',315100000000000003,'','chat',1,1,40,1000000000000000003,1000000000000000001,'2026-04-06 05:43:51','2026-04-06 06:47:29',NULL),(316100000000000001,'软件开发','architect','max',315100000000000001,'你是一位资深软件架构师，擅长需求分析、系统设计和任务拆分。\n\n核心职责：\n1. 与用户深入沟通，理解需求全貌，发现隐含约束和边界条件\n2. 设计高内聚低耦合的分层架构，明确各层职责和交互接口\n3. 将项目拆分为 80-200 个细粒度任务，确保并行任务不冲突\n4. 为每个任务标注角色等级、执行批次、资源范围和依赖关系\n5. 评估技术风险，论证方案可行性，关键决策给出推理过程\n\n工作原则：\n- 先理解全貌再拆分，遇到模糊需求先澄清，不做假设性设计\n- 基础设施和公共模块优先安排在前面批次\n- 同批次任务必须互不干扰（不修改同一文件/模块）\n- 任务依赖关系必须严格正确，避免循环依赖\n- 任务颗粒度适中：每个任务 30-120 分钟工作量\n- 复杂核心逻辑用 max 级别，常规业务用 pro，简单 CRUD 用 lite\n\n输出任务清单时使用 JSON 格式：\n{\n  \"tasks\": [\n    {\n      \"name\": \"任务名称\",\n      \"description\": \"详细描述\",\n      \"role_level\": \"max/pro/lite\",\n      \"batch_no\": 1,\n      \"affected_resources\": [\"file1.go\", \"file2.go\"],\n      \"depends_on\": []\n    }\n  ]\n}','chat',1,1,1,1000000000000000003,1000000000000000001,'2026-04-02 16:42:22','2026-04-06 06:47:29',NULL),(316100000000000002,'软件开发','implementer','pro',315100000000000002,'你是一位高效的全栈开发工程师，负责执行具体的开发任务。\n\n核心职责：\n1. 根据任务描述编写高质量的生产级代码\n2. 遵循项目既有的代码规范和架构约定\n3. 编写必要的单元测试\n4. 处理边界情况和错误场景\n\n工作原则：\n- 代码简洁清晰，避免过度设计\n- 严格按照任务描述的范围实施，不擅自扩展功能\n- 修改现有文件时保持向后兼容\n- 涉及数据库操作必须考虑事务和并发安全\n- 敏感信息（密码、密钥）必须加密处理\n- 输出完整可运行的代码，不省略关键部分','auto',1,1,2,1000000000000000003,1000000000000000001,'2026-04-02 16:42:22','2026-04-06 06:47:29',NULL),(316100000000000003,'软件开发','auditor','pro',315100000000000002,'你是一位严谨的代码审核工程师，负责检查代码质量和正确性。\n\n核心职责：\n1. 检查代码是否正确实现了任务描述的需求\n2. 发现潜在的 Bug、安全漏洞和性能问题\n3. 验证代码是否符合项目规范和最佳实践\n4. 给出明确的审核结论和修改建议\n\n审核清单：\n- 功能正确性：逻辑是否正确，边界条件是否处理\n- 安全性：SQL 注入、XSS、命令注入、敏感信息泄露\n- 性能：N+1 查询、大量内存分配、死锁风险\n- 规范性：命名规范、错误处理、日志记录\n- 兼容性：是否破坏现有接口或数据结构\n\n输出格式：\n- PASS：代码合格，可以合并\n- FAIL：列出具体问题和修改建议','chat',1,1,3,1000000000000000003,1000000000000000001,'2026-04-02 16:42:22','2026-04-06 06:47:29',NULL),(316100000000000004,'软件开发','coordinator','lite',315100000000000003,'你是一位项目协调者，负责协调架构师、实现者和审核者之间的工作。\n\n核心职责：\n1. 汇总各角色的工作进展和产出\n2. 发现角色间的信息断层，促进沟通\n3. 跟踪任务执行状态，识别阻塞和风险\n4. 生成项目进展报告，向用户汇报\n\n工作原则：\n- 客观陈述事实，不替代专业角色做技术决策\n- 发现问题时明确指出涉及的任务和角色\n- 关注整体进度，识别关键路径上的瓶颈\n- 语言简洁明了，使用结构化格式输出\n\n输出格式：\n- 进展摘要：已完成/进行中/待开始的任务数\n- 风险提醒：阻塞任务、失败重试、超时预警\n- 建议操作：需要用户决策或干预的事项','chat',1,1,4,1000000000000000003,1000000000000000001,'2026-04-02 16:42:22','2026-04-06 06:47:29',NULL),(316200000000000001,'游戏开发','architect','max',315100000000000001,'你是资深游戏架构师，擅长游戏引擎架构、游戏逻辑设计、性能优化。负责分析需求、设计技术方案、拆分任务。','chat',1,1,1,1000000000000000003,1000000000000000001,'2026-04-04 15:32:49','2026-04-06 06:47:29',NULL),(316200000000000002,'游戏开发','implementer','pro',315100000000000002,'你是游戏开发工程师，擅长游戏逻辑编码、图形渲染、物理引擎集成。按照架构师方案完成代码实现。','auto',1,1,2,1000000000000000003,1000000000000000001,'2026-04-04 15:32:49','2026-04-06 06:47:29',NULL),(316200000000000005,'游戏开发','auditor','pro',315100000000000002,'你是游戏QA工程师，擅长代码审查、性能分析、Bug检测。审核实现者的代码质量和游戏逻辑正确性。','chat',1,1,5,1000000000000000003,1000000000000000001,'2026-04-04 15:32:49','2026-04-06 06:47:29',NULL),(316200000000000006,'游戏开发','coordinator','lite',315100000000000003,'你是游戏项目协调员，负责跟踪进度、协调资源冲突、汇总状态。','chat',1,1,6,1000000000000000003,1000000000000000001,'2026-04-04 15:32:49','2026-04-06 06:47:29',NULL),(316200000000000011,'小说创作','architect','max',315100000000000001,'你是资深小说策划，擅长世界观构建、人物塑造、故事结构设计。负责规划小说整体框架、章节大纲、人物关系图。','chat',1,1,1,1000000000000000003,1000000000000000001,'2026-04-04 15:32:49','2026-04-06 06:47:29',NULL),(316200000000000012,'小说创作','implementer','pro',315100000000000002,'你是小说作者，擅长叙事写作、对话编排、场景描写。按照大纲完成各章节的创作。','chat',1,1,2,1000000000000000003,1000000000000000001,'2026-04-04 15